def encode(message):
    vowels = "aeiouAEIOU"
    result = []
    for ch in message:
        if ch in vowels:
            # Shift vowel by 2 places in alphabet
            if ch.islower():
                new_char = chr((ord(ch) - ord('a') + 2) % 26 + ord('a'))
            else:
                new_char = chr((ord(ch) - ord('A') + 2) % 26 + ord('A'))
            result.append(new_char.swapcase())
        else:
            result.append(ch.swapcase())
    return ''.join(result)

